mapper.select:
SELECT product_id, product_name, price, stock, create_time, update_time
FROM t_stock



        AND product_id = #{query.productId}




        AND product_name LIKE '%' || #{query.productName} || '%'




        AND price >= #{query.minPrice}


        AND price <= #{query.maxPrice}




        AND stock >= #{query.minStock}


        AND stock <= #{query.maxStock}




        AND create_time >= #{query.startTime}


        AND create_time <= #{query.endTime}




        AND update_time >= #{query.updateStartTime}


         AND update_time <= #{query.updateEndTime} 


ORDER BY create_time DESC
